def solve(grid):
    from itertools import combinations
    rows = len(grid)
    cols = len(grid[0])
    five_cells = set()
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 5:
                five_cells.add((r,c))
    blocks = []
    for r in range(rows-1):
        for c in range(cols-1):
            if grid[r][c]==5 and grid[r][c+1]==5 and grid[r+1][c]==5 and grid[r+1][c+1]==5:
                blocks.append((r,c))
    def check_remaining(cells_used):
        remaining = five_cells - cells_used
        if not remaining:
            return True
        for r,c in remaining:
            has_neighbor = False
            for dr,dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                if (r+dr,c+dc) in remaining:
                    has_neighbor = True
                    break
            if not has_neighbor:
                return False
        for r,c in remaining:
            h_nbrs = sum(1 for dc in [-1,1] if (r,c+dc) in remaining)
            v_nbrs = sum(1 for dr in [-1,1] if (r+dr,c) in remaining)
            if h_nbrs > 0 and v_nbrs > 0:
                return False
        return True
    for size in range(len(blocks), 0, -1):
        for combo in combinations(range(len(blocks)), size):
            cells_used = set()
            ok = True
            for idx in combo:
                r0, c0 = blocks[idx]
                block_cells = {(r0+dr, c0+dc) for dr in range(2) for dc in range(2)}
                if block_cells & cells_used:
                    ok = False
                    break
                cells_used |= block_cells
            if not ok:
                continue
            if check_remaining(cells_used):
                result = [row[:] for row in grid]
                for r in range(rows):
                    for c in range(cols):
                        if grid[r][c] == 5:
                            result[r][c] = 8 if (r,c) in cells_used else 2
                return result
    result = [row[:] for row in grid]
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 5:
                result[r][c] = 2
    return result

