def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    ones = set((r,c) for r in range(rows) for c in range(cols) if grid[r][c] == 1)
    best_center = None
    best_additions = None
    best_count = float('inf')
    for cr_x2 in range(0, rows*2+1):
        for cc_x2 in range(0, cols*2+1):
            cr, cc = cr_x2/2.0, cc_x2/2.0
            valid = True
            additions = set()
            for r,c in ones:
                mr, mc = round(2*cr-r), round(2*cc-c)
                if 0 <= mr < rows and 0 <= mc < cols:
                    if (mr, mc) not in ones:
                        if grid[mr][mc] != 0:
                            valid = False
                            break
                        additions.add((mr, mc))
                else:
                    valid = False
                    break
            if valid and additions:
                for r,c in additions:
                    mr, mc = round(2*cr-r), round(2*cc-c)
                    if (mr, mc) not in ones:
                        valid = False
                        break
                if valid and len(additions) < best_count:
                    best_center = (cr, cc)
                    best_additions = additions
                    best_count = len(additions)
    result = [row[:] for row in grid]
    if best_additions:
        for r,c in best_additions:
            result[r][c] = 2
    return result

