def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    cells = {}
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] != 0:
                cells[(r,c)] = grid[r][c]
    min_r = min(r for r,c in cells)
    min_c = min(c for r,c in cells)
    color = None
    for v in cells.values():
        if v != 2:
            color = v
            break
    directions = []
    for (r,c), v in cells.items():
        if v == 2:
            dr = r - min_r
            dc = c - min_c
            dir_r = 2*dr - 1
            dir_c = 2*dc - 1
            directions.append((dir_r, dir_c))
    result = [[0]*cols for _ in range(rows)]
    for dir_r, dir_c in directions:
        k = 0
        while True:
            br = min_r + dir_r * k
            bc = min_c + dir_c * k
            any_valid = False
            for dr in range(2):
                for dc in range(2):
                    r, c = br + dr, bc + dc
                    if 0 <= r < rows and 0 <= c < cols:
                        result[r][c] = color
                        any_valid = True
            if not any_valid:
                break
            k += 1
    for dr in range(2):
        for dc in range(2):
            r, c = min_r + dr, min_c + dc
            if 0 <= r < rows and 0 <= c < cols:
                result[r][c] = color
    return result

