def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    colors = {}
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] != 0:
                color = grid[r][c]
                if color not in colors:
                    colors[color] = []
                colors[color].append((r, c))
    result = [row[:] for row in grid]
    for color, positions in colors.items():
        if len(positions) == 2:
            (r1, c1), (r2, c2) = positions
            dr = 1 if r2 > r1 else -1
            dc = 1 if c2 > c1 else -1
            r, c = r1, c1
            while True:
                result[r][c] = color
                if r == r2 and c == c2:
                    break
                r += dr
                c += dc
    return result

